atom-text-editor[mini] {
  padding-left: 0;
  border-radius: @component-border-radius;
  color: @text-color-highlight;
  border: 1px solid @input-border-color;
  background-color: @input-background-color;
  padding-left: @component-padding/2;

  &,
  &.editor {
    .placeholder-text {
      color: @text-color-subtle;
    }
    .selection .region {
      background-color: @input-selection-color;
    }
    .cursor {
      border-color: @base-accent-color;
      border-width: 2px;
    }
  }

  &.is-focused,
  &.is-focused.editor {
    .focus();
    background-color: @input-background-color-focus;
    .selection .region {
      background-color: @input-selection-color-focus;
    }
  }
}

& when (@variationPopupLoading) {
    .ui.loading.popup {
        cursor: default;
        pointer-events: @loadingPointerEvents;
        user-select: none;
        & * {
            opacity: @loadingOpacity;
        }
        &::after {
            position: absolute;
            content: "";
            top: 50%;
            left: 50%;
            margin: @loaderMargin;
            width: @loaderSize;
            height: @loaderSize;
            animation: loader @loaderSpeed infinite linear;
            border: @loaderLineWidth solid @loaderLineColor;
            border-radius: @circularRadius;
            box-shadow: 0 0 0 1px transparent;
            visibility: visible;
            z-index: @loaderLineZIndex;
        }
    }
}

pre {
  display: block;
  padding: ((@line-height-computed - 1) / 2);
  margin: 0 0 (@line-height-computed / 2);
  font-size: (@font-size-base - 1); // 14px to 13px
  line-height: @line-height-base;
  color: @pre-color;
  word-break: break-all;
  word-wrap: break-word;
  background-color: @pre-bg;
  border: 1px solid @pre-border-color;
  border-radius: @border-radius-base;

  // Account for some code outputs that place code tags in pre tags
  code {
    padding: 0;
    font-size: inherit;
    color: inherit;
    white-space: pre-wrap;
    background-color: transparent;
    border-radius: 0;
  }
}

&-cell {
  justify-content: center;
  align-items: center;

  &:hover {
    background-color: @calendar-bg;
  }

  &-display {
    font: @calendar-card-body-cell-display-font;
    padding-top: @calendar-card-body-cell-display-padding;
    padding-bottom: @calendar-card-body-cell-display-padding;
    text-align: center;
    border-radius: @calendar-card-body-cell-display-border-radius;
    transition: all @calendar-transition-duration @calendar-transition-timing-function;

    &:hover {
      box-shadow: inset 0 0 0 1px @calendar-highlight-color;
      transition: box-shadow @calendar-transition-duration @calendar-transition-timing-function;
    }
  }

  &--now {
    .@{prefix}-calendar__table-body-cell-display {
      color: @calendar-highlight-color;
      background-color: @calendar-body-cell-check-bg-color;
      position: relative;
    }
  }
}

@media (min-width: @grid-float-breakpoint) {
  width: auto;
  border-top: 0;
  box-shadow: none;

  &.collapse {
    display: block !important;
    visibility: visible !important;
    height: auto !important;
    padding-bottom: 0; // Override default setting
    overflow: visible !important;
  }

  &.in {
    overflow-y: visible;
  }

  // Undo the collapse side padding for navbars with containers to ensure
  // alignment of right-aligned contents.
  .navbar-fixed-top &,
  .navbar-static-top &,
  .navbar-fixed-bottom & {
    padding-left: 0;
    padding-right: 0;
  }
}

@media (min-width: 992px) {
  // Show the sidenav on larger screens
  .sidebar {
    display: block;
    padding-top: 65px;
  }
  .sidebar .nav > .active > ul {
    display: block;
  }
  // Widen the fixed sidebar
  .sidebar.affix,
  .sidebar.affix-bottom {
    width: 213px;
  }
  .sidebar.affix {
    position: fixed; // Undo the static from mobile first approach
    top: 15px;
    bottom: 0;
    overflow: auto;
  }
  .sidebar.affix-bottom {
    position: absolute; // Undo the static from mobile first approach
  }
  .sidebar.affix .sidenav,
  .sidebar.affix-bottom .sidenav {
    margin-top: 10px;
    margin-bottom: 0;
  }
}

@media (min-width: @screen-sm) {
  // Inline-block all the things for "inline"
  .form-group  {
    display: inline-block;
    margin-bottom: 0;
    vertical-align: middle;
  }

  // In navbar-form, allow folks to *not* use `.form-group`
  .form-control {
    display: inline-block;
  }

  // Remove default margin on radios/checkboxes that were used for stacking, and
  // then undo the floating of radios and checkboxes to match (which also avoids
  // a bug in WebKit: https://github.com/twbs/bootstrap/issues/1969).
  .radio,
  .checkbox {
    display: inline-block;
    margin-top: 0;
    margin-bottom: 0;
    padding-left: 0;
  }
  .radio input[type="radio"],
  .checkbox input[type="checkbox"] {
    float: none;
    margin-left: 0;
  }
}

a.list-group-item {
  color: @list-group-link-color;

  .list-group-item-heading {
    color: @list-group-link-heading-color;
  }

  // Hover state
  &:hover,
  &:focus {
    text-decoration: none;
    background-color: @list-group-hover-bg;
  }

  // Active class on item itself, not parent
  &.active,
  &.active:hover,
  &.active:focus {
    z-index: 2; // Place active items above their siblings for proper border styling
    color: @list-group-active-color;
    background-color: @list-group-active-bg;
    border-color: @list-group-active-border;

    // Force color to inherit for custom content
    .list-group-item-heading {
      color: inherit;
    }
    .list-group-item-text {
      color: lighten(@list-group-active-bg, 40%);
    }
  }
}

@media (min-width: @screen-md-min) {
  .bs-docs-sidebar .nav > .active > ul {
    display: block;
  }
  // Widen the fixed sidebar
  .bs-docs-sidebar.affix,
  .bs-docs-sidebar.affix-bottom {
    width: 213px;
  }
  .bs-docs-sidebar.affix {
    position: fixed; // Undo the static from mobile first approach
    top: 20px;
  }
  .bs-docs-sidebar.affix-bottom {
    position: absolute; // Undo the static from mobile first approach
  }
  .bs-docs-sidebar.affix-bottom .bs-docs-sidenav,
  .bs-docs-sidebar.affix .bs-docs-sidenav {
    margin-top: 0;
    margin-bottom: 0;
  }
}

&-footer {
  padding: @modal-inner-padding;
  text-align: right; // right align buttons
  border-top: 1px solid @modal-footer-border-color;
  &:extend(.clearfix all); // clear it in case folks use .pull-* classes on buttons

  // Properly space out buttons
  .btn + .btn {
    margin-left: 5px;
    margin-bottom: 0; // account for input[type="submit"] which gets the bottom margin like all other inputs
  }
  // but override that for button groups
  .btn-group .btn + .btn {
    margin-left: -1px;
  }
  // and override it for block buttons as well
  .btn-block + .btn-block {
    margin-left: 0;
  }
}

@media only screen and (max-width: @largestMobileScreen) {
  .ui.stackable.menu {
    flex-direction: column;
  }
  .ui.stackable.menu .item {
    width: 100% !important;
  }
  .ui.stackable.menu .item:before {
    position: absolute;
    content: '';
    top: auto;
    bottom: 0px;
    left: 0px;
    width: 100%;
    height: @dividerSize;
    background: @verticalDividerBackground;
  }

  .ui.stackable.menu .left.menu,
  .ui.stackable.menu .left.item {
    margin-right: 0 !important;
  }
  .ui.stackable.menu .right.menu,
  .ui.stackable.menu .right.item {
    margin-left: 0 !important;
  }

  .ui.stackable.menu .right.menu,
  .ui.stackable.menu .left.menu {
    flex-direction: column;
  }
}

