		}

[data-column="0"].column-RootSidebar, .nylas-outline-view .heading{
  color: @sidebar-fg-color;
  .scrollbar-track{
    border:none;
    background: @sidebar-bg;
  }
  padding-bottom: 12px;
  background: @sidebar-bg;
  #account-switcher .item-container.dropping, .account-sidebar .item-container.dropping{
    background: @sidebar-active-item-bg!important;
    &.active{
      background: @sidebar-bg-hl;
    }
    color: @sidebar-fg-color;
    border-radius: 3px;
    img{
      background-color: @sidebar-fg-color;
    }
  }
  .sidebar-activity {
    background: @sidebar-bg;
    color: @sidebar-fg-color-hl;
    box-shadow: none;
    .item, .item .inner span{
      color: @sidebar-fg-color-hl;
      border-color: @sidebar-bg;
    }
  }
}

& .content {
    margin-top: @circularStepContentMarginTop;
    padding: @circularStepContentPadding;
    &.center.aligned {
        margin-top: @circularStepContentCenterAlignedMarginTop;
        & .title {
            padding: @circularStepContentPadding;
            margin-left: @circularStepContentCenterAlignedMarginLeft;
            background: @circularStepContentCenterAlignedBackground;
        }
    }
    &.bottom.aligned {
        margin-top: @circularStepContentBottomAlignedMarginTop;
    }
    &:not(.aligned) .title + .description {
        margin-top: @circularStepContentDescriptionDistance;
    }
}

atom-text-editor[mini],
  atom-text-editor[mini]::shadow {
    .text(heading);
    color: @text-color-highlight;
    font-size: 24px;
    line-height: 32px;
    height: auto;
    max-height: none;
    background-color: transparent;
    margin: 0 -@component-padding*2;
    padding: 0 @component-padding*2 @component-padding @component-padding*2;
    border: 0;
    border-radius: 0;
    border-bottom: 1px solid @base-border-color;


    &.is-focused:hover,
    &:hover {
      border-top: 0 !important;
      border-left: 0 !important;
      border-right: 0 !important;
      border-bottom: 1px solid @base-border-color !important;
      background-color: transparent !important;
    }
  }

i {
  font-size: 1.1em;
  line-height: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  max-height: 44px !important;
  max-width: fit-content !important;
  width: auto;
  height: auto;
  flex-shrink: 0;

  &.fa-kit {
    padding: 0 !important;
    // Fix the <i> to the same size it occupies after the font loads.
    // Without this, the ::before glyph expands the <i> when the font arrives,
    // growing the container and causing the visible resize flash.
    width: 1.1em;
    height: 1.1em;
    line-height: 1.1em;
    overflow: hidden;
  }
}

&.selected.expanded + .children,
    &.hovered.expanded + .children {
      border-bottom-left-radius: 5px;
      border-bottom-right-radius: 5px;
      padding-bottom: 5px !important;
      box-shadow: inset 0 0 30px 0 @eh-children-shadow;
      border-color: transparent !important;
      border-bottom: 1px solid @- !important; .contrast(@global-background, 10%);

      // highlight pseudo elements of selected node
      > li .webkit-html-pseudo-element:first-child {
        color: @xml-pseudo-highlighted !important;
      }

      // fade closing tag of parent
      > li:last-of-type .webkit-html-tag.close {
        opacity: 0.5 !important;
      }
    }

& .app-chrome-item:hover {
    .minimize {
        background-image      : url('icons/minimize.svg') !important;
        background-size       : 13px 13px;
        // background-position: center;
        background-repeat     : no-repeat;
    }

    .minmax {
        background-image   : url('icons/minmax.svg') !important;
        background-size    : 10px 10px;
        background-position: center;
        background-repeat  : no-repeat;
    }

    .minmax.restore {
        background-image      : url('icons/maxmin.svg') !important;
        background-size       : 12px 12px;
        // background-position: center;
        background-repeat     : no-repeat;
    }

    .close {
        background-image       : url('icons/close.svg') !important;
        background-size        : 13px 13px;
        // basckground-position: inherit;
        background-repeat      : no-repeat;
    }
}

& when (@variationTableOverflowing) {
    & when (@variationTableOverflowingShort) {
        .ui.overflowing.table.short {
            max-height: @overflowingMobileMaxHeight * 0.75;
        }
    }
    & when (@variationTableOverflowingVeryShort) {
        .ui.overflowing.table[class*="very short"] {
            max-height: @overflowingMobileMaxHeight * 0.5;
        }
    }
    .ui.overflowing.table {
        max-height: @overflowingMobileMaxHeight;
    }
    & when (@variationTableOverflowingLong) {
        .ui.overflowing.table.long {
            max-height: @overflowingMobileMaxHeight * 2;
        }
    }
    & when (@variationTableOverflowingVeryLong) {
        .ui.overflowing.table[class*="very long"] {
            max-height: @overflowingMobileMaxHeight * 3;
        }
    }
}

& when (@variationTableDisabled) {
    .ui.ui.ui.inverted.table tr.disabled td,
    .ui.ui.ui.inverted.table tr td.disabled,
    .ui.inverted.table tr.disabled:hover td,
    .ui.inverted.table tr:hover td.disabled {
        pointer-events: none;
        color: @invertedDisabledTextColor;
    }
    .ui.ui.ui.inverted.table tr td.disabled:not([class="disabled"]),
    .ui.inverted.table tr.disabled:not([class="disabled"]) td,
    .ui.inverted.table tr.disabled td[class]:not(.disabled),
    .ui.inverted.table tr:hover td.disabled:not([class="disabled"]) {
        color: @disabledTextColor;
    }
}

& when (@variationAccordionVeryCompact) {
    .ui[class*="very compact"].accordion@{notStyled} > .title,
    .ui[class*="very compact"].accordion@{notStyled} .accordion > .title {
        padding: @titlePaddingVeryCompact;
    }

    .ui[class*="very compact"].accordion@{notStyled} .title ~ .content,
    .ui[class*="very compact"].accordion@{notStyled} .accordion .title ~ .content {
        padding: @contentPaddingVeryCompact;
    }

    .ui[class*="very compact"].styled.accordion > .title,
    .ui[class*="very compact"].styled.accordion .accordion > .title {
        padding: @styledTitlePaddingVeryCompact;
    }

    .ui[class*="very compact"].styled.accordion .title ~ .content,
    .ui[class*="very compact"].styled.accordion .accordion .title ~ .content {
        padding: @styledContentPaddingVeryCompact;
    }
}

&-head {
  height: @card-head-height;
  line-height: @card-head-height;
  background: @card-head-background;
  border-bottom: @border-width-base @border-style-base @border-color-split;
  padding: 0 @card-padding-base;
  border-radius: @border-radius-sm @border-radius-sm 0 0;
  .clearfix;
  margin-bottom: -1px; // Fix card grid overflow bug: https://gw.alipayobjects.com/zos/rmsportal/XonYxBikwpgbqIQBeuhk.png
  display: flex;

  &-title {
    font-size: @font-size-lg;
    text-overflow: ellipsis;
    max-width: 100%;
    overflow: hidden;
    white-space: nowrap;
    color: @card-head-color;
    font-weight: 500;
    display: inline-block;
    flex: 1;
  }
}

#message-list .message-item-wrap .message-item-white-wrap.composer-outer-wrap,
.window-type-composer [data-column="0"] .composer-inner-wrap .composer-action-bar-wrap,
#message-list .message-item-wrap .message-item-white-wrap.composer-outer-wrap .composer-action-bar-wrap,
.layout-mode-popout  .composer-full-window .composer-inner-wrap .composer-action-bar-plugins{
  background: @white;
  .btn.btn-toolbar{
    &:nth-child(3){
      .content-mask{
        &:first-child{
          margin-left: -5px;
        }
        &:last-child{
          margin-left: -2px;
          margin-right: -4px;
        }
      }
    }
    &.btn-trash{
      padding: @composer-btn-padding;
    }
    &.btn-attach{
      padding-left: 12px;
      padding-right: 12px;
    }
    &.btn-send-later{
      padding: @send-later-btn-padding;
    }
  }
}

& when (@variationAccordionInverted) {
    .ui.inverted.basic.styled.accordion > .title,
    .ui.inverted.basic.styled.accordion .accordion > .title {
        background: transparent;
        color: @invertedBasicStyledTitleColor;
    }
    .ui.inverted.basic.styled.accordion > .title:hover,
    .ui.inverted.basic.styled.accordion .accordion > .title:hover {
        background: transparent;
        color: @invertedBasicStyledTitleHoverColor;
    }
    .ui.inverted.basic.styled.accordion[open] > .title,
    .ui.inverted.basic.styled.accordion .active.title,
    .ui.inverted.basic.styled.accordion .accordion[open] > .title,
    .ui.inverted.basic.styled.accordion .accordion .active.title {
        background: transparent;
        color: @invertedBasicStyledActiveTitleColor;
    }
}
